INSERT INTO `mobile_specs` (`id`, `mobile_id`, `spec_key`, `spec_value`) VALUES ('4', '1', 'Memory', '128GB 4GB RAM, 128GB 6GB RAM, 128GB 8GB RAM, 256GB 8GB RAM; microSDXC (uses shared SIM slot)');
