INSERT INTO `mobile_specs` (`id`, `mobile_id`, `spec_key`, `spec_value`) VALUES ('8', '1', 'Video capture', 'Rear camera: 1080p@30fps, gyro-EIS; Front camera: 1080p@30fps.');
