INSERT INTO `pages` (`id`, `title`, `content`, `published`, `slug`, `created_at`, `updated_at`) VALUES ('3', 'কিভাবে একটি সফল ব্লগ ওয়েবসাইট তৈরি করবেন?', '<p></p><div><span>&lt;!DOCTYPE</span><span> html</span><span>&gt;</span></div><div><span>&lt;</span><span>html</span> <span>lang</span><span>=</span><span>\"bn\"</span><span>&gt;</span></div><div><span>&lt;</span><span>head</span><span>&gt;</span></div><div>    <span>&lt;</span><span>meta</span> <span>charset</span><span>=</span><span>\"UTF-8\"</span><span>&gt;</span></div><div>    <span>&lt;</span><span>meta</span> <span>name</span><span>=</span><span>\"viewport\"</span> <span>content</span><span>=</span><span>\"width=device-width, initial-scale=1.0\"</span><span>&gt;</span></div><div>    <span>&lt;</span><span>title</span><span>&gt;</span>ব্লগ টেস্ট পেইজ - আধুনিক লেআউট<span>&lt;/</span><span>title</span><span>&gt;</span></div><div>    <span>&lt;</span><span>script</span> <span>src</span><span>=</span><span>\"https://cdn.tailwindcss.com\"</span><span>&gt;&lt;/</span><span>script</span><span>&gt;</span></div><div>    <span>&lt;</span><span>link</span> <span>href</span><span>=</span><span>\"https://fonts.googleapis.com/css2?family=Hind+Siliguri:wght@300;400;500;600;700&amp;display=swap\"</span> <span>rel</span><span>=</span><span>\"stylesheet\"</span><span>&gt;</span></div><div>    <span>&lt;</span><span>style</span><span>&gt;</span></div><div>        <span>body</span> <span>{</span></div><div>            <span>font-family:</span> <span>\'Hind Siliguri\'</span><span>,</span> <span>sans-serif</span><span>;</span></div><div>            <span>scroll-behavior:</span> <span>smooth</span><span>;</span></div><div>        <span>}</span></div><div>    <span>&lt;/</span><span>style</span><span>&gt;</span></div><div><span>&lt;/</span><span>head</span><span>&gt;</span></div><div><span>&lt;</span><span>body</span> <span>class</span><span>=</span><span>\"bg-gray-50 text-gray-800\"</span><span>&gt;</span></div><br><div>    <span>&lt;!-- নেভিগেশন বার --&gt;</span></div><div>    <span>&lt;</span><span>nav</span> <span>class</span><span>=</span><span>\"bg-white shadow-md sticky top-0 z-50\"</span><span>&gt;</span></div><div>        <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"max-w-6xl mx-auto px-4\"</span><span>&gt;</span></div><div>            <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"flex justify-between items-center h-16\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"flex-shrink-0\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>h1</span> <span>class</span><span>=</span><span>\"text-2xl font-bold text-blue-600\"</span><span>&gt;</span>আমার ব্লগ<span>&lt;/</span><span>h1</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"hidden md:flex space-x-8\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"text-gray-600 hover:text-blue-600 transition\"</span><span>&gt;</span>হোম<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"text-gray-600 hover:text-blue-600 transition\"</span><span>&gt;</span>ক্যাটাগরি<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"text-gray-600 hover:text-blue-600 transition\"</span><span>&gt;</span>জনপ্রিয়<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"text-gray-600 hover:text-blue-600 transition\"</span><span>&gt;</span>যোগাযোগ<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"md:hidden\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>button</span> <span>class</span><span>=</span><span>\"text-gray-600 focus:outline-none\"</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>svg</span> <span>class</span><span>=</span><span>\"h-6 w-6\"</span> <span>fill</span><span>=</span><span>\"none\"</span> <span>stroke</span><span>=</span><span>\"currentColor\"</span> <span>viewBox</span><span>=</span><span>\"0 0 24 24\"</span><span>&gt;</span></div><div>                            <span>&lt;</span><span>path</span> <span>stroke-linecap</span><span>=</span><span>\"round\"</span> <span>stroke-linejoin</span><span>=</span><span>\"round\"</span> <span>stroke-width</span><span>=</span><span>\"2\"</span> <span>d</span><span>=</span><span>\"M4 6h16M4 12h16m-7 6h7\"</span><span>&gt;&lt;/</span><span>path</span><span>&gt;</span></div><div>                        <span>&lt;/</span><span>svg</span><span>&gt;</span></div><div>                    <span>&lt;/</span><span>button</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>        <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>    <span>&lt;/</span><span>nav</span><span>&gt;</span></div><br><div>    <span>&lt;!-- হিরো সেকশন (ফিচার্ড ইমেজ) --&gt;</span></div><div>    <span>&lt;</span><span>header</span> <span>class</span><span>=</span><span>\"max-w-4xl mx-auto mt-10 px-4\"</span><span>&gt;</span></div><div>        <span>&lt;</span><span>div</sp