<span>\"lg:col-span-2 space-y-8\"</span><span>&gt;</span></div><div>            <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"prose prose-lg max-w-none text-gray-700 leading-relaxed\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-xl font-medium text-gray-900 mb-6\"</span><span>&gt;</span>ব্লগিং বর্তমান সময়ে নিজের দক্ষতা বা অভিজ্ঞতা শেয়ার করার অন্যতম সেরা মাধ্যম। আজকের এই টেস্ট পেইজে আমরা ব্লগের বিভিন্ন এলিমেন্ট পরীক্ষা করব।<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                </div><div>                <span>&lt;</span><span>h3</span> <span>class</span><span>=</span><span>\"text-2xl font-bold text-gray-900 mt-8 mb-4\"</span><span>&gt;</span>১. ব্লগের গুরুত্ব<span>&lt;/</span><span>h3</span><span>&gt;</span></div><div>                <span>&lt;</span><span>p</span><span>&gt;</span>একটি ভালো ব্লগ পোস্ট শুধুমাত্র তথ্য দেয় না, বরং পাঠকদের সাথে একটি সম্পর্ক তৈরি করে। এখানে আপনি আপনার লেখার ধরন বা ফন্ট স্টাইল কেমন হবে তা দেখে নিতে পারেন।<span>&lt;/</span><span>p</span><span>&gt;</span></div><br><div>                <span>&lt;</span><span>blockquote</span> <span>class</span><span>=</span><span>\"border-l-4 border-blue-600 bg-blue-50 p-6 italic text-gray-800 my-8 rounded-r-lg\"</span><span>&gt;</span></div><div>                    \"লেখালেখি হলো মনের ভাব প্রকাশের শ্রেষ্ঠ উপায়। একটি পরিষ্কার ও সুন্দর ওয়েবসাইট পাঠকের পড়ার অভিজ্ঞতাকে বহুগুণ বাড়িয়ে দেয়।\"</div><div>                <span>&lt;/</span><span>blockquote</span><span>&gt;</span></div><br><div>                <span>&lt;</span><span>h3</span> <span>class</span><span>=</span><span>\"text-2xl font-bold text-gray-900 mt-8 mb-4\"</span><span>&gt;</span>২. লিস্ট স্টাইল টেস্ট<span>&lt;/</span><span>h3</span><span>&gt;</span></div><div>                <span>&lt;</span><span>ul</span> <span>class</span><span>=</span><span>\"list-disc list-inside space-y-2 mb-6\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;</span>সুন্দর ইউজার ইন্টারফেস।<span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;</span>দ্রুত লোডিং স্পিড।<span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;</span>মোবাইল ফ্রেন্ডলি ডিজাইন।<span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;</span>সার্চ ইঞ্জিন অপ্টিমাইজেশন (SEO)।<span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>ul</span><span>&gt;</span></div><br><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"bg-gray-100 p-6 rounded-xl my-10 border border-gray-200\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-center font-semibold\"</span><span>&gt;</span>[এখানে একটি ইন-আর্টিকেল ইমেজ বা বিজ্ঞাপন থাকবে]<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><br><div>                <span>&lt;</span><span>h3</span> <span>class</span><span>=</span><span>\"text-2xl font-bold text-gray-900 mt-8 mb-4\"</span><span>&gt;</span>৩. কোড ব্লক এবং অন্যান্য<span>&lt;/</span><span>h3</span><span>&gt;</span></div><div>                <span>&lt;</span><span>p</span><span>&gt;</span>যদি আপনার ব্লগটি প্রযুক্তি বিষয়ক হয়, তবে কোড ব্লকগুলো দেখতে এরকম হতে পারে:<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                <span>&lt;</span><span>pre</span> <span>class</span><span>=</span><span>\"bg-gray-900 text-green-400 p-4 rounded-lg overflow-x-auto my-6 text-sm\"</span><span>&gt;</span></div><div><span>&lt;</span><span>code</span><span>&gt;</span>function greet() {</div><div>  console.log(\"স্বাগতম আমার ব্লগে!\");</div><div>}<span>&lt;/</span><span>code</span><span>&gt;&lt;/</span><span>pre</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><br><div>            <span>&lt;!-- ট্যাগ সেকশন --&gt;</span></div><div>            <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"pt-8 border-t border-gray-200 flex flex-wrap gap-2\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>span</span> <span>class</span><span>=</span><span>\"bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-sm hover:bg-blue-100 hover:text-blue-700 cursor-pointer transition\"</span><span>&gt;</span>#ব্লগিং<span>&lt;/</span><span>span</span><span>&gt;</span></div><div>                <span>&lt;</span><span>span</span> <span>class</span><span>=</span><span>\"bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-sm hover:bg-blue-100 hover:text-blue-700 cursor-pointer transition\"</span><span>&gt;</span>#টিপস<span>&lt;/</span><span>span</span><span>&gt;</span></div><div>                <span>&lt;</span><span>span</span> <span>class</span><span>=</span><span>\"bg-gray-200 text-gray-700 px-3 py-1 rounded-full text-sm hover:bg-blue-100 hover:text-blue-700 cursor-pointer transition\"</span><span>&gt;</span>#ক্যারিয়ার<span>&lt;/</span><span>span</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><br><div>            <span>&lt;!-- কমেন্ট সেকশন টেস্ট --&gt;</span></div><div>            <span>&lt;</span><span>section</span> <span>class</span><span>=</span><span>\"bg-white p-6 rounded-2xl shadow-sm border border-gray-100 mt-10\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h4</span> <span>class</span><span>=</span><span>\"text-xl font-bold mb-6\"</span><span>&gt;</span>আপনার মন্তব্য জানান<span>&lt;/</span><span>h4</span><span>&gt;</span></div><div>                <span>&lt;</span><span>textarea</span> <span>class</span><span>=</span><span>\"w-full p-4 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none mb-4\"</span> <span>rows</span><span>=</span><span>\"4\"</span> <span>placeholder</span><span>=</span><span>\"এখানে লিখুন...\"</span><span>&gt;&lt;/</span><span>textarea</span><span>&gt;</span></div><div>                <span>&lt;</span><span>button</span> <span>class</span><span>=</span><span>\"bg-blue-600 text-white px-6 py-2 rounded-lg font-semibold hover:bg-blue-700 transition\"</span><span>&gt;</span>মন্তব্য সাবমিট করুন<span>&lt;/</span><span>button</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>section</span><span>&gt;</span></div><div>        <span>&lt;/</span><span>article</span><span>&gt;</span></div><br><div>        <span>&lt;!-- সাইডবার এলাকা --&gt;</span></div><div>        <span>&lt;</span><span>aside</span> <span>class</span><span>=</span><span>\"space-y-10\"</span><span>&gt;</span></div><div>            <span>&lt;!-- লেখক পরিচিতি --&gt;</span></div><div>            <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"bg-white p-6 rounded-2xl shadow-sm border border-gray-100\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h4</span> <span>class</span><span>=</span><span>\"text-lg font-bold mb-4 border-b pb-2\"</span><span>&gt;</span>লেখকের পরিচিতি<span>&lt;/</span><span>h4</span><span>&gt;</span></div><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"flex items-center space-x-4\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-xl\"</span><span>&gt;</span>ইউ<span>&lt;/</span><span>div</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>div</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"font-bold\"</span><span>&gt;</span>ব্যবহারকারীর নাম<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-sm text-gray-500\"</span><span>&gt;</span>কন্টেন্ট রাইটার ও ডেভেলপার<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                    <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"mt-4 text-sm text-gray-600\"</span><span>&gt;</span>আমি প্রযুক্তি এবং জীবনশৈলী নিয়ে লিখতে ভালোবাসি। আমার ব্লগ ভিজিট করার জন্য ধন্যবাদ।<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><br><div>            <span>&lt;!-- জনপ্রিয় পোস্ট --&gt;</span></div><div>            <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"bg-white p-6 rounded-2xl shadow-sm border border-gray-100\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h4</span> <span>class</span><span>=</span><span>\"text-lg font-bold mb-4 border-b pb-2\"</span><span>&gt;</span>জনপ্রিয় পোস্ট<span>&lt;/</span><span>h4</span><span>&gt;</span></div><div>                <span>&lt;</span><span>ul</span> <span>class</span><span>=</span><span>\"space-y-4\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span> <span>class</span><span>=</span><span>\"group cursor-pointer\"</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-sm font-semibold group-hover:text-blue-600 transition\"</span><span>&gt;</span>ফ্রিল্যান্সিং শুরু করার সহজ উপায়<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-xs text-gray-400 mt-1\"</span><span>&gt;</span>জানুয়ারি ২৫, ২০২৬<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                    <span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span> <span>class</span><span>=</span><span>\"group cursor-pointer\"</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-sm font-semibold group-hover:text-blue-600 transition\"</span><span>&gt;</span>সেরা ৫টি এআই টুলস<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-xs text-gray-400 mt-1\"</span><span>&gt;</span>জানুয়ারি ২২, ২০২৬<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                    <span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span> <span>class</span><span>=</span><span>\"group cursor-pointer\"</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-sm font-semibold group-hover:text-blue-600 transition\"</span><span>&gt;</span>ওয়েব ডেভেলপমেন্ট গাইডলাইন<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                        <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-xs text-gray-400 mt-1\"</span><span>&gt;</span>জানুয়ারি ২০, ২০২৬<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                    <span>&lt;/</span><span>li</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>ul</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><br><div>            <span>&lt;!-- নিউজলেটার --&gt;</span></div><div>            <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"bg-blue-600 p-6 rounded-2xl shadow-lg text-white\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h4</span> <span>class</span><span>=</span><span>\"text-lg font-bold mb-2 text-center\"</span><span>&gt;</span>নতুন আপডেট পেতে চান?<span>&lt;/</span><span>h4</span><span>&gt;</span></div><div>                <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-sm text-blue-100 text-center mb-4\"</span><span>&gt;</span>আমাদের নিউজলেটারে সাবস্ক্রাইব করুন।<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>                <span>&lt;</span><span>input</span> <span>type</span><span>=</span><span>\"email\"</span> <span>placeholder</span><span>=</span><span>\"আপনার ইমেইল\"</span> <span>class</span><span>=</span><span>\"w-full p-2 rounded text-gray-900 mb-3 text-sm outline-none\"</span><span>&gt;</span></div><div>                <span>&lt;</span><span>button</span> <span>class</span><span>=</span><span>\"w-full bg-white text-blue-600 font-bold py-2 rounded hover:bg-blue-50 transition\"</span><span>&gt;</span>সাবস্ক্রাইব<span>&lt;/</span><span>button</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>        <span>&lt;/</span><span>aside</span><span>&gt;</span></div><br><div>    <span>&lt;/</span><span>main</span><span>&gt;</span></div><br><div>    <span>&lt;!-- ফুটার সেকশন --&gt;</span></div><div>    <span>&lt;</span><span>footer</span> <span>class</span><span>=</span><span>\"bg-gray-900 text-gray-400 py-12 mt-20\"</span><span>&gt;</span></div><div>        <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"max-w-6xl mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-8\"</span><span>&gt;</span></div><div>            <span>&lt;</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h5</span> <span>class</span><span>=</span><span>\"text-white font-bold text-lg mb-4\"</span><span>&gt;</span>আমাদের সম্পর্কে<span>&lt;/</span><span>h5</span><span>&gt;</span></div><div>                <span>&lt;</span><span>p</span> <span>class</span><span>=</span><span>\"text-sm leading-relaxed\"</span><span>&gt;</span>আমরা মানসম্মত কন্টেন্ট এবং প্রযুক্তির সঠিক তথ্য পাঠকদের কাছে পৌঁছে দিতে কাজ করি।<span>&lt;/</span><span>p</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>            <span>&lt;</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h5</span> <span>class</span><span>=</span><span>\"text-white font-bold text-lg mb-4\"</span><span>&gt;</span>গুরুত্বপূর্ণ লিঙ্ক<span>&lt;/</span><span>h5</span><span>&gt;</span></div><div>                <span>&lt;</span><span>ul</span> <span>class</span><span>=</span><span>\"text-sm space-y-2\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>প্রাইভেসি পলিসি<span>&lt;/</span><span>a</span><span>&gt;&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>শর্তাবলী<span>&lt;/</span><span>a</span><span>&gt;&lt;/</span><span>li</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>li</span><span>&gt;&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>ডিএমসিএ (DMCA)<span>&lt;/</span><span>a</span><span>&gt;&lt;/</span><span>li</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>ul</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>            <span>&lt;</span><span>div</span><span>&gt;</span></div><div>                <span>&lt;</span><span>h5</span> <span>class</span><span>=</span><span>\"text-white font-bold text-lg mb-4\"</span><span>&gt;</span>অনুসরণ করুন<span>&lt;/</span><span>h5</span><span>&gt;</span></div><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"flex space-x-4\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>ফেসবুক<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>টুইটার<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>লিঙ্কডইন<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>        <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>        <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"max-w-6xl mx-auto px-4 mt-8 pt-8 border-t border-gray-800 text-center text-xs\"</span><span>&gt;</span></div><div>            © ২০২৬ আমার ব্লগ ওয়েবসাইট। সর্বস্বত্ব সংরক্ষিত।</div><div>        <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>    <span>&lt;/</span><span>footer</span><span>&gt;</span></div><br><div><span>&lt;/</span><span>body</span><span>&gt;</span></div><div><span>&lt;/</span><span>html</span><span>&gt;</span></div>', '0', NULL, '2026-01-29 02:40:43', '2026-01-29 02:40:43');
