INSERT INTO `pages` (`id`, `title`, `content`, `published`, `slug`, `created_at`, `updated_at`) VALUES ('5', 'কিভাবে একটি সফল ব্লগ ওয়েবসাইট তৈরি করবেন?', '<p><img src=\"https://www.reuters.com/resizer/v2/PK2PBKJ2ARPY3OU5E6A6KOUUXY.jpg?auth=93245273f6001300c2f7ba5e586fd2d563d433fd8c38205e3901569e82548120&amp;width=1920&amp;quality=80\" alt=\"The U.S. Capitol building in Washington\">ব্লগিং বর্তমান সময়ে নিজের দক্ষতা বা অভিজ্ঞতা শেয়ার করার অন্যতম সেরা মাধ্যম। আজকের এই টেস্ট পেইজে আমরা ব্লগের বিভিন্ন এলিমেন্ট পরীক্ষা করব।</p><p>১. ব্লগের গুরুত্ব</p><p>একটি ভালো ব্লগ পোস্ট শুধুমাত্র তথ্য দেয় না, বরং পাঠকদের সাথে একটি সম্পর্ক তৈরি করে। এখানে আপনি আপনার লেখার ধরন বা ফন্ট স্টাইল কেমন হবে তা দেখে নিতে পারেন।</p><p>\"লেখালেখি হলো মনের ভাব প্রকাশের শ্রেষ্ঠ উপায়। একটি পরিষ্কার ও সুন্দর ওয়েবসাইট পাঠকের পড়ার অভিজ্ঞতাকে বহুগুণ বাড়িয়ে দেয়।\"২. লিস্ট স্টাইল টেস্ট</p><ul><li>সুন্দর ইউজার ইন্টারফেস।</li><li>দ্রুত লোডিং স্পিড।</li><li>মোবাইল ফ্রেন্ডলি ডিজাইন।</li><li>সার্চ ইঞ্জিন অপ্টিমাইজেশন (SEO)।</li></ul><p><img src=\"https://www.reuters.com/resizer/v2/MDW7ADBZFBMXNOI2MKKZ2OGMDE.jpg?auth=3c295d64ed639a9d3c2cf5ada984e1a798eedc1cb097c735b08bd99d72c9a848&amp;width=1920&amp;quality=80\" alt=\"U.S. Department of Labor headquarters, in Washington\"></p>', '1', 'kibhabe-ekti-sphl-blog-oebsait-toiri-krben', '2026-01-29 02:44:49', '2026-01-30 20:44:14');
INSERT INTO `pages` (`id`, `title`, `content`, `published`, `slug`, `created_at`, `updated_at`) VALUES ('6', 'কিভাবে একটি সফল ব্লগ ওয়েবসাইট তৈরি করবেন?', '<div>\n            <div>\n                <div>\n                    আমার ব্লগ\n                </div>\n                <div>\n                    <a href=\"#\">হোম</a>\n                    <a href=\"#\">ক্যাটাগরি</a>\n                    <a href=\"#\">জনপ্রিয়</a>\n                    <a href=\"#\">যোগাযোগ</a>\n                </div>\n                <div>\n                    \n                        \n                            \n                        \n                    \n                </div>\n            </div>\n        </div>\n    \n\n    \n    \n        <div>\n            <div>\n                <div>\n                    <span>প্রযুক্তি</span>\n                    কিভাবে একটি সফল ব্লগ ওয়েবসাইট তৈরি করবেন?\n                    <p>প্রকাশিত: ২৮ জানুয়ারি, ২০২৬ | ৫ মিনিট পড়ার সময়</p>\n                </div>\n            </div>\n        </div>\n    \n\n    \n    \n        \n        \n        \n            <div>\n                <p>ব্লগিং বর্তমান সময়ে নিজের দক্ষতা বা অভিজ্ঞতা শেয়ার করার অন্যতম সেরা মাধ্যম। আজকের এই টেস্ট পেইজে আমরা ব্লগের বিভিন্ন এলিমেন্ট পরীক্ষা করব।</p>\n                \n                ১. ব্লগের গুরুত্ব\n                <p>একটি ভালো ব্লগ পোস্ট শুধুমাত্র তথ্য দেয় না, বরং পাঠকদের সাথে একটি সম্পর্ক তৈরি করে। এখানে আপনি আপনার লেখার ধরন বা ফন্ট স্টাইল কেমন হবে তা দেখে নিতে পারেন।</p>\n\n                \n                    \"লেখালেখি হলো মনের ভাব প্রকাশের শ্রেষ্ঠ উপায়। একটি পরিষ্কার ও সুন্দর ওয়েবসাইট পাঠকের পড়ার অভিজ্ঞতাকে বহুগুণ বাড়িয়ে দেয়।\"\n                \n\n                ২. লিস্ট স্টাইল টেস্ট\n                <ul>\n                    <li>সুন্দর ইউজার ইন্টারফেস।</li>\n                    <li>দ্রুত লোডিং স্পিড।</li>\n                    <li>মোবাইল ফ্রেন্ডলি ডিজাইন।</li>\n                    <li>সার্চ ইঞ্জিন অপ্টিমাইজেশন (SEO)।</li>\n                </ul>\n\n                <div>\n                    <p>[এখানে একটি ইন-আর্টিকেল ইমেজ বা বিজ্ঞাপন থাকবে]</p>\n                </div>\n\n                ৩. কোড ব্লক এবং অন্যান্য\n                <p>যদি আপনার ব্লগটি প্রযুক্তি বিষয়ক হয়, তবে কোড ব্লকগুলো দেখতে এরকম হতে পারে:</p>\n                \nfunction greet() {\n  console.log(\"স্বাগতম আমার ব্লগে!\");\n}\n            </div>\n\n            \n            <div>\n                <span>#ব্লগিং</span>\n                <span>#টিপস</span>\n                <span>#ক্যারিয়ার</span>\n            </div>\n\n            \n            \n                আপনার মন্তব্য জানান\n                \n                মন্তব্য সাবমিট করুন\n            \n        \n\n        \n        \n            \n            <div>\n                লেখকের পরিচিতি\n                <div>\n                    <div>ইউ</div>\n                    <div>\n                        <p>ব্যবহারকারীর নাম</p>\n                        <p>কন্টেন্ট রাইটার ও ডেভেলপার</p>\n                    </div>\n                </div>\n                <p>আমি প্রযুক্তি এবং জীবনশৈলী নিয়ে লিখতে ভালোবাসি। আমার ব্লগ ভিজিট করার জন্য ধন্যবাদ।</p>\n            </div>\n\n            \n            <div>\n                জনপ্রিয় পোস্ট\n                <ul>\n                    <li>\n                        <p>ফ্রিল্যান্সিং শুরু করার সহজ উপায়</p>\n                        <p>জানুয়ারি ২৫, ২০২৬</p>\n                    </li>\n                    <li>\n                        <p>সেরা ৫টি এআই টুলস</p>\n                        <p>জানুয়ারি ২২, ২০২৬</p>\n                    </li>\n                    <li>\n                        <p>ওয়েব ডেভেলপমেন্ট গাইডলাইন</p>\n                        <p>জানুয়ারি ২০, ২০২৬</p>\n                    </li>\n                </ul>\n            </div>\n\n            \n            <div>\n                নতুন আপডেট পেতে চান?\n                <p>আমাদের নিউজলেটারে সাবস্ক্রাইব করুন।</p>\n                \n                সাবস্ক্রাইব\n            </div>\n        \n\n    \n\n    \n    \n        <div>\n            <div>\n                আমাদের সম্পর্কে\n                <p>আমরা মানসম্মত কন্টেন্ট এবং প্রযুক্তির সঠিক তথ্য পাঠকদের কাছে পৌঁছে দিতে কাজ করি।</p>\n            </div>\n            <div>\n                গুরুত্বপূর্ণ লিঙ্ক\n                <ul>\n                    <li><a href=\"#\">প্রাইভেসি পলিসি</a></li>\n                    <li><a href=\"#\">শর্তাবলী</a></li>\n                    <li><a href=\"#\">ডিএমসিএ (DMCA)</a></li>\n                </ul>\n            </div>\n            <div>\n                অনুসরণ করুন\n                <div>\n                    <a href=\"#\">ফেসবুক</a>\n                    <a href=\"#\">টুইটার</a>\n                    <a href=\"#\">লিঙ্কডইন</a>\n                </div>\n            </div>\n        </div>\n        <div>\n            © ২০২৬ আমার ব্লগ ওয়েবসাইট। সর্বস্বত্ব সংরক্ষিত।\n        </div>\n    \n\n', '0', NULL, '2026-01-29 02:46:07', '2026-01-29 02:47:28');
