INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('1', 'Report: Apple to switch up its iPhone launch cycle with the 18 series', '<p><img src=\"/uploads/content/posts/img_1768577146_2237.jpg\" alt=\"\">&lt;p&gt;&amp;amp;lt;p&amp;amp;gt;While we’re just weeks away from the launch of the iPhone 17 series, \nrumors about the next generation of iPhones are continuing to make their\n way in. The latest report from &amp;amp;lt;em&amp;amp;gt;ET News&amp;amp;lt;/em&amp;amp;gt; suggests that Apple is looking to switch up its iPhone launch cycle, starting with the iPhone 18 series.&amp;amp;lt;/p&amp;amp;gt;\n\n&amp;amp;lt;img class=\"inline-image\" width=\"1200\" height=\"799\" src=\"https://fdn.gsmarena.com/imgroot/news/25/08/report-apple-to-switch-up-iphone-release-schedule/-1200w5/gsmarena_002.jpg\" alt=\"Report: Apple to switch up its iPhone launch cycle with the 18 series \"&amp;amp;gt;\n\n&amp;amp;lt;p&amp;amp;gt;Cupertino will reportedly have two separate iPhone launch events for \nthe iPhone 18 series. The first keynote will be held in September 2026 \nand will see the debut of the iPhone 18 Air, 18 Pro, 18 Pro Max and the \nlong-rumored &amp;amp;lt;a href=\"https://www.gsmarena.com/apple_iphone_fold_5g-13804.php\"&amp;amp;gt;foldable iPhone&amp;amp;lt;/a&amp;amp;gt;.&amp;amp;lt;/p&amp;amp;gt;\n\n&amp;amp;lt;p&amp;amp;gt;The vanilla iPhone 18 will be relegated to a second event in early \n2027 alongside the iPhone 18e. This release schedule is expected to \ncarry on with the iPhone 19 Air, Pro and Fold models launching in \nSeptember of 2027, while the vanilla iPhone 19 and affordable 19e would \nbe introduced in H1 2028.&amp;amp;lt;/p&amp;amp;gt;\n\n&amp;amp;lt;p class=\"article-source\"&amp;amp;gt;&amp;amp;lt;a href=\"https://www.etnews.com/20250813000323\" target=\"_blank\" rel=\"noopener noreferrer\"&amp;amp;gt;Source&amp;amp;lt;/a&amp;amp;gt; (&amp;amp;lt;em&amp;amp;gt;in Korean&amp;amp;lt;/em&amp;amp;gt;)&amp;amp;lt;/p&amp;amp;gt;&lt;/p&gt;</p>', 'admin', 'report-apple-to-switch-up-its-iphone-launch-cycle-with-the-18-series', '1', '0', '2025-08-20 00:00:01', '2026-01-16 21:26:19', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('2', 'Microsoft graduates Copilot Studio extension for VS Code to general availability', '<a href=\"https://cdn.neowin.com/news/images/uploaded/2025/05/1746781447_vscode.jpg\" target=\"_blank\" rel=\"noreferrer noopener\"><img alt=\"The Visual Studio Code logo\" src=\"https://cdn.neowin.com/news/images/uploaded/2025/05/1746781447_vscode_story.jpg\"></a><p>Microsoft has just released the <a href=\"https://www.neowin.net/news/microsofts-copilot-studio-gets-a-boost-with-computer-use-tool/\" target=\"_blank\" rel=\"noreferrer noopener\">Copilot Studio</a> extension for <a href=\"https://www.neowin.net/news/visual-studio-code-1107-launches-with-multi-agent-orchestration-and-agent-hq/\" target=\"_blank\" rel=\"noreferrer noopener\">Visual Studio Code</a>, graduating it to the status of Generally Available (GA). With the Copilot Studio extension, developers can build, edit, and manage AI agents directly within VS Code. This transforms agent creation from a web-based UI task into a professional software development workflow.</p><p>Copilot Studio is primarily a low-code platform, but by bringing the extension to the IDE, Microsoft wants to enable pro-code capabilities that allow teams to use existing tools like Git, CI/CD pipelines, and advanced AI assistants to build more complex agents for the enterprise.</p><p>The Copilot Studio extension supports local agent definitions where you can clone the full agent definition rather than just a solution file to your local machine. This includes topics, tools, triggers, settings, and knowledge references. It also delivers a pro-code workflow with the following features:</p><ul><li><span>Syntax highlighting and IntelliSense</span> deliver code completion and error checking while editing agent YAML files.</li><li><span>Side-by-side diffing</span> allows you to compare local changes against the cloud version before applying them.</li><li>Finally, <span>syncing</span> allows you to use the “Apply Changes” command to push updates back to the cloud for testing.</li></ul><p>Microsoft <a href=\"https://devblogs.microsoft.com/microsoft365dev/copilot-studio-extension-for-visual-studio-code-is-now-generally-available/\" target=\"_blank\" rel=\"noreferrer noopener\">also said</a> that now your agent is represented as local files, you can use your standard GitHub or GitLab workflows for version control, pull requests, and code reviews. You can also use GitHub Copilot or Claude Code within VS Code to help write new topics or troubleshoot logic in your agent’s definition.</p><a href=\"https://cdn.neowin.com/news/images/uploaded/2026/01/1768456059_mcs-vscode.webp\" target=\"_blank\" rel=\"noreferrer noopener\"><img alt=\"The Copilot Studio extension in VS Code marketplace\" src=\"https://cdn.neowin.com/news/images/uploaded/2026/01/1768456059_mcs-vscode_story.webp\"></a><p>Before the GA of this extension, managing agents with dozens of topics could be difficult to track. Now you can use VS Code’s global search to find specific logic across all topics instantly. You can also integrate agent definitions into your automated deployment processes so that your agents move through Dev, Test, and Prod environments with the same rigor as your web apps. It also enables multi-developer collaboration by allowing to your leverage standard branch-based development</p><p><span></span><span></span></p><p>To get started, go to the VS Code Marketplace and search for “Microsoft Copilot Studio”, then install it. You then need to sign in to your Microsoft account associated with your Copilot Studio environment. ‍ৃ আমি h</p>', '', 'microsoft-graduates-copilot-studio-extension-for-vs-code-to-general-availability', '1', '0', '2026-01-17 03:29:52', '2026-02-01 02:48:46', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('3', 'দেশে আনুষ্ঠানিক কার্যক্রম শুরু করলো হোস্টিং ডটকমHosting.com officially starts operations in the country', '&lt;p&gt;&lt;img src=&quot;/uploads/content/posts/img_1768635859_5795.webp&quot; alt=&quot;&quot;&gt;&lt;/p&gt;&lt;p&gt;বিশ্বখ্যাত হোস্টিং সেবাদাতা প্রতিষ্ঠান ‘হোস্টিং ডটকম’ (Hosting.com) বাংলাদেশে আনুষ্ঠানিকভাবে ব্যবসায়িক কার্যক্রম শুরু করেছে।&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;বুধবার (১৪ জানুয়ারি) রাজধানীর হোটেল শেরাটনে প্রধান অতিথি হিসাবে উপস্থিত থেকে এ কার্যক্রমের আনুষ্ঠানিক উদ্বোধন করেন ডাক, টেলিযোগাযোগ ও তথ্যপ্রযুক্তি মন্ত্রণালয়ে দায়িত্বপ্রাপ্ত প্রধান উপদেষ্টার বিশেষ সহকারী ফয়েজ আহমদ তৈয়্যব।&lt;/p&gt;&lt;p&gt;&lt;/p&gt;&lt;p&gt;&lt;/p&gt;&lt;div&gt;&lt;/div&gt;&lt;div&gt;&lt;/div&gt;&lt;p&gt;অনুষ্ঠানে জানানো হয়, হোস্টিং ডটকম গ্রাহকদের জন্য বাংলা ভাষায় কাস্টমার সেবা প্রদান করবে। একই সঙ্গে স্থানীয় কারেন্সিতে মূল্য পরিশোধ ও সাশ্রয়ী মূল্যে হোস্টিং সেবা নিশ্চিত করবে প্রতিষ্ঠানটি।&amp;nbsp;&lt;/p&gt;&lt;p&gt;এ সময় বিশেষ অতিথি হিসাবে উপস্থিত ছিলেন হোস্টিং ডটকমের প্রধান নির্বাহী কর্মকর্তা (সিইও) সেব ডি লেমোস, সহপ্রতিষ্ঠাতা ও ও প্রধান পরিচালন কর্মকর্তা (সিওও) পানোস কেসিসিস, চিফ প্রোডাক্ট অফিসার বেন গ্যাবলার, হেড অব ওয়েবসাইট অ্যান্ড কনটেন্ট ড্যাফনি মনরোড্যাফনি মনরো এবং তথ্য ও যোগাযোগ প্রযুক্তি বিভাগের সচিব শীষ হায়দার চৌধুরী। এছাড়া স্থানীয় প্রযুক্তি বিশেষজ্ঞ ও ইন্ডাস্ট্রি প্রতিনিধিরা উপস্থিত ছিলেন।&lt;/p&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;p&gt;অনুষ্ঠানে প্রধান অতিথি ফয়েজ আহমদ তৈয়্যব বলেন, বাংলাদেশে হোস্টিং ডটকমের কার্যক্রম শুরু হওয়ার ফলে সার্ভার অবকাঠামো, ক্লাউডভিত্তিক সমাধান, এআই বট প্রযুক্তি, সার্চ ইঞ্জিন অপটিমাইজেশন এবং ডোমেইন ব্যবসাসহ বিভিন্ন ডিজিটাল সেবা নতুন গতি পাবে। এতে বাজারে প্রতিযোগিতা বাড়বে, মানসম্মত সেবার বিস্তার ঘটবে এবং ব্যবহারকারীদের জন্য ইতিবাচক অভিজ্ঞতা ও নতুন সম্ভাবনার দুয়ার খুলে যাবে। একই সঙ্গে এটি একটি শক্তিশালী নতুন ইকোসিস্টেম গড়ে তুলবে, যা নতুন কর্মসংস্থান সৃষ্টি করবে, দক্ষতা উন্নয়নকে ত্বরান্বিত করবে এবং দেশে জ্ঞান ও প্রযুক্তিনির্ভর উদ্ভাবনের পরিসরকে আরও বিস্তৃত করবে।&lt;/p&gt;&lt;p&gt;হোস্টিং ডটকমের সিইও সেব ডি লেমোস বলেন, দাম ও প্যাকেজ নিয়ে আমরা প্রচুর ফিডব্যাক পেয়েছি এবং বিষয়টি আমরা অত্যন্ত গুরুত্বের সঙ্গে বিবেচনা করছি। খুব শিগগিরই বাংলাদেশি গ্রাহকদের জন্য দাম ও প্যাকেজের ক্ষেত্রে বিশেষ কিছু উদ্যোগ নেওয়া হবে। প্রতিটি দেশের নিজস্ব সংস্কৃতি ও চাহিদা থাকে, সেটিও আমরা মাথায় রেখেছি। হোস্টিং ডটকমের অবকাঠামোয় ৩০ লাখের বেশি ওয়েবসাইট সক্রিয়, প্রতি ১৫ সেকেন্ডে নতুন একটি ওয়েবসাইট যুক্ত হচ্ছে এবং বিশ্বের ২০টির বেশি ডাটা সেন্টার ও এক হাজারের বেশি এক্সপার্টের সমন্বয়ে আমরা দ্রুত, স্থিতিশীল ও নিরবচ্ছিন্ন সেবা নিশ্চিত করছি।&lt;/p&gt;&lt;p&gt;হোস্টিং ডটকমের বাংলাদেশ অপারেশন ম্যানেজার ইমরান হোসেন বলেন, হোস্টিং ডটকমের বৈশ্বিক মানের হোস্টিং ও ডাটা অবকাঠামো বাংলাদেশি উদ্যোক্তা, স্টার্টআপ এবং ডিজিটাল ব্যবসার জন্য নতুন সম্ভাবনার দ্বার উন্মুক্ত করবে। এর ফলে স্থানীয় প্রযুক্তি ইকোসিস্টেম আরও শক্তিশালী হবে, নতুন কর্মসংস্থানের সুযোগ সৃষ্টি হবে এবং বাংলাদেশকে একটি আঞ্চলিক ডিজিটাল হাব হিসেবে গড়ে তোলার পথে এটি গুরুত্বপূর্ণ ভূমিকা রাখবে।&lt;/p&gt;', '', '', '0', '0', '2026-01-17 13:45:15', '2026-02-01 01:21:51', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('4', 'WOW.LLC (WOW Exchange) – কীভাবে সাইন আপ করে রেফার করে আয় করবেন', '&lt;p&gt;&lt;span&gt;﻿&lt;/span&gt;আসসালমুয়ালাইকুম ।&lt;br&gt;আশা করি ট্রিকবিডি ফ্যামেলির সবাই ভালো আছেন।&lt;/p&gt;&lt;p&gt;বর্তমান সময়ে অনলাইনে আয় করার জন্য ক্রিপ্টোকারেন্সি ভিত্তিক প্ল্যাটফর্মগুলো বেশ জনপ্রিয়। এর মধ্যে WOW.LLC (WOW Exchange) একটি নতুন ক্রিপ্টো ট্রেডিং ও রিওয়ার্ড প্ল্যাটফর্ম, যেখানে সহজভাবে সাইন আপ করে রেফার করার মাধ্যমে আয় করা যায়।&lt;/p&gt;&lt;p&gt;WOW.LLC কী?&lt;/p&gt;&lt;p&gt;WOW.LLC (WOW Exchange) হলো একটি ক্রিপ্টোকারেন্সি ট্রেডিং ও রিওয়ার্ড প্ল্যাটফর্ম, যেখানে ব্যবহারকারীরা:&lt;br&gt;*অ্যাকাউন্ট খুলতে পারে&lt;br&gt;*বিভিন্ন ক্যাম্পেইন ও বোনাস পেতে পারে&lt;br&gt;*রেফার প্রোগ্রামের মাধ্যমে আয় করতে পারে&lt;/p&gt;&lt;p&gt;এটি নতুন ব্যবহারকারীদের জন্য সহজ ইন্টারফেস এবং বোনাস সুবিধা দেয়।&lt;/p&gt;&lt;p&gt;কীভাবে WOW.LLC তে সাইন আপ করবেন?&lt;/p&gt;&lt;p&gt;WOW.LLC তে সাইন আপ করা খুবই সহজ। নিচের ধাপগুলো অনুসরণ করুন:&lt;/p&gt;&lt;p&gt;Step 1: ওয়েবসাইটে যান&lt;/p&gt;&lt;p&gt;আপনার ব্রাউজার থেকে ভিজিট করুন:&lt;br&gt;&lt;img alt=&quot;👉&quot; src=&quot;https://s.w.org/images/core/emoji/15.0.3/svg/1f449.svg&quot;&gt;&amp;nbsp;&lt;a href=&quot;https://wow.llc/signup?ref=ZHGRDF&quot; target=&quot;_blank&quot; rel=&quot;noreferrer noopener&quot;&gt;WOW Exchange&lt;/a&gt;&lt;/p&gt;&lt;p&gt;&lt;a href=&quot;https://trickbd.com/wp-content/uploads/2026/01/19/IMG_8272.png&quot; target=&quot;_blank&quot; rel=&quot;noreferrer noopener&quot;&gt;&lt;img src=&quot;https://trickbd.com/wp-content/uploads/2026/01/19/IMG_8272.png&quot; alt=&quot;&quot; width=&quot;1200&quot; height=&quot;1200&quot;&gt;&lt;/a&gt;&lt;/p&gt;&lt;p&gt;&lt;img alt=&quot;🔹&quot; src=&quot;https://s.w.org/images/core/emoji/15.0.3/svg/1f539.svg&quot;&gt;&amp;nbsp;Step 2: তথ্য পূরণ করুন&lt;/p&gt;&lt;p&gt;আপনাকে নিচের তথ্য দিতে হবে:&lt;br&gt;*Email Address&lt;br&gt;*Password&lt;br&gt;*(অপশনাল) Referral Code&lt;/p&gt;&lt;p&gt;চাইলে Google Account দিয়েও সাইন আপ করা যায়।&lt;/p&gt;&lt;p&gt;&lt;img alt=&quot;🔹&quot; src=&quot;https://s.w.org/images/core/emoji/15.0.3/svg/1f539.svg&quot;&gt;&amp;nbsp;Step 3: Email Verification&lt;/p&gt;&lt;p&gt;রেজিস্ট্রেশন শেষ হলে আপনার ইমেইলে একটি ভেরিফিকেশন লিংক যাবে।&lt;br&gt;লিংকে ক্লিক করে অ্যাকাউন্ট ভেরিফাই করুন।&lt;/p&gt;&lt;p&gt;&lt;img alt=&quot;✅&quot; src=&quot;https://s.w.org/images/core/emoji/15.0.3/svg/2705.svg&quot;&gt;&amp;nbsp;এখন আপনার WOW Exchange অ্যাকাউন্ট রেডি।&lt;/p&gt;&lt;p&gt;WOW.LLC এ কীভাবে রেফার করে আয় করবেন?&lt;/p&gt;&lt;p&gt;Referral Link শেয়ার করুন এবং প্রতি রেফারেল এ ১০ WOW টোকেন পাবেন&lt;/p&gt;&lt;p&gt;&lt;img alt=&quot;💰&quot; src=&quot;https://s.w.org/images/core/emoji/15.0.3/svg/1f4b0.svg&quot;&gt;&amp;nbsp;যত বেশি রেফার, আয় তত বেশি।&lt;/p&gt;&lt;p&gt;আনলিমিটেড রেফারেল করবেন কিভাবে ?&lt;br&gt;রেফার লিঙ্ক কপি করে Via Browser দিয়ে ফেক রেফার করে আনলিমিটেড Earn করতে পারবেন ।&lt;/p&gt;', '', '', '0', NULL, '2026-01-19 20:31:43', '2026-02-01 01:01:31', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('5', '৯ দিন বন্ধ থাকবে আল-আরাফাহ্‌ ইসলামী ব্যাংকের ডিজিটাল সেবা', '&lt;p&gt;&lt;/p&gt;&lt;p&gt;&lt;/p&gt;&lt;p&gt;&lt;img src=&quot;https://media.prothomalo.com/prothomalo-bangla%2F2024-04%2Feed58c0c-0eee-471e-a27a-8ce433db655f%2Fbb8e7a66_bb73_43a8_8783_60fb63979a7c.jfif?rect=0%2C0%2C1200%2C800&amp;amp;w=375&amp;amp;auto=format%2Ccompress&amp;amp;fmt=avif&quot; alt=&quot;৯ দিন বন্ধ থাকবে আল-আরাফাহ্‌ ইসলামী ব্যাংকের ডিজিটাল সেবা&quot;&gt;&lt;/p&gt;&lt;p&gt;&lt;/p&gt;&lt;p&gt;&lt;/p&gt;&lt;p&gt;&lt;/p&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;p&gt;গ্রাহকদের জন্য আধুনিক ও নিরাপদ ব্যাংকিং সেবা নিশ্চিতে প্রযুক্তিগত সক্ষমতা বৃদ্ধি বা সিস্টেম আপগ্রেডেশন কাজ শুরু করছে আল-আরাফাহ্‌ ইসলামী ব্যাংক। এ জন্য ব্যাংকটির বিভিন্ন সেবা ৩০ জানুয়ারি থেকে ৭ ফেব্রুয়ারি পর্যন্ত ৯ দিন বন্ধ থাকবে। কোন সেবা কোন দিন বন্ধ থাকবে, তা ইতিমধ্যে জানানো হয়েছে। এতে সম্মতি জানিয়ে বাংলাদেশ ব্যাংক একটি প্রজ্ঞাপন জারি করেছে।&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;&lt;p&gt;কেন্দ্রীয় ব্যাংকের প্রজ্ঞাপনে বলা হয়েছে, ৩০ জানুয়ারি থেকে ৭ ফেব্রুয়ারি পর্যন্ত এটিএম ও ইন্টারনেট ব্যাংকিংসহ সব অনলাইন ব্যাংকিং সেবা সম্পূর্ণ বন্ধ থাকবে। নগদ লেনদেনসহ সব শাখা ও উপশাখা পয়লা ফেব্রুয়ারি থেকে ৩ ফেব্রুয়ারি পর্যন্ত বন্ধ রাখা হবে। ৫ ফেব্রুয়ারি সকাল ১০টা থেকে শুধু নগদ লেনদেন ও সীমিত পরিসরে শাখাভিত্তিক ব্যাংকিং সেবা আবার চালু হবে। ৮ ফেব্রুয়ারি সব ধরনের নিয়মিত ও অনলাইন ব্যাংকিং সেবা পূর্ণাঙ্গভাবে চালু হবে।&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', '', '', '0', NULL, '2026-01-27 12:15:33', '2026-02-01 00:52:45', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('6', 'সিসকস', '&lt;p&gt;&amp;lt;p&amp;gt;্নন&amp;lt;/p&amp;gt;&lt;img src=&quot;/home/tdhuedhn/broxbhai/public/uploads/content/whatsapp_image_2025_10_30_at_2_15_39_pm_1769855239.jpeg&quot; alt=&quot;&quot;&gt;&lt;/p&gt;', '', '', '0', NULL, '2026-01-29 02:43:12', '2026-01-31 16:27:42', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('7', 'BroxLab launch 2026', '&lt;img src=&quot;/home/tdhuedhn/broxbhai/public/uploads/content/whatsapp_image_2025_10_30_at_2_15_39_pm_1769853548_4484.jpeg&quot; alt=&quot;&quot;&gt;&lt;img src=&quot;/home/tdhuedhn/broxbhai/public/uploads/content/whatsapp_image_2025_10_30_at_2_15_39_pm_1769852935_6984.jpeg&quot; alt=&quot;&quot;&gt;&lt;p&gt;​🚀 যাত্রা শুরু হলো BroxLab-এর! 🌐&lt;/p&gt;&lt;p&gt;​প্রযুক্তির দ্রুত পরিবর্তনশীল বিশ্বে আপনাকে আপ-টু-ডেট রাখতে আমাদের নতুন উদ্যোগ &lt;strong&gt;BroxLab Digital Tech Hub&lt;/strong&gt;। আমরা বিশ্বাস করি সঠিক তথ্যই পারে আপনার ডিজিটাল জীবনকে সহজ করতে।&lt;/p&gt;&lt;p&gt;​&lt;strong&gt;🔍 আমাদের প্ল্যাটফর্মে যা যা থাকছে:&lt;/strong&gt;&lt;/p&gt;&lt;ul&gt;\n&lt;li&gt;​&lt;strong&gt;স্মার্টফোন ডায়েরি:&lt;/strong&gt; লেটেস্ট স্মার্টফোনের ইন-ডেপথ স্পেসিফিকেশন ও নিখুঁত তুলনা।&lt;/li&gt;\n&lt;li&gt;​&lt;strong&gt;গ্যাজেট জোন:&lt;/strong&gt; নিত্যনতুন গ্যাজেট রিভিউ এবং টেক দুনিয়ার গরম সব খবর।&lt;/li&gt;\n&lt;li&gt;​&lt;strong&gt;ক্যারিয়ার বুস্ট:&lt;/strong&gt; অনলাইন ইনকাম (Freelancing) এবং ক্যারিয়ার গাইডলাইন।&lt;/li&gt;\n&lt;li&gt;​&lt;strong&gt;ডেইলি লাইফ হ্যাকস:&lt;/strong&gt; ব্যাংকিং সেবা এবং নির্ভরযোগ্য চাকরির আপডেট।&lt;/li&gt;\n&lt;/ul&gt;&lt;p&gt;​আমাদের লক্ষ্য একটাই—জটিল প্রযুক্তিকে আপনার কাছে সহজভাবে পৌঁছে দেওয়া।&lt;/p&gt;&lt;p&gt;​🔗 &lt;strong&gt;ভিজিট করুন আমাদের ওয়েবসাইট:&lt;/strong&gt; &lt;a href=&quot;https://www.google.com/search?q=http://BroxLab.online&quot; target=&quot;_blank&quot; rel=&quot;noreferrer noopener&quot;&gt;BroxLab.online&lt;/a&gt;&lt;/p&gt;&lt;p&gt;​প্রযুক্তির এই রোমাঞ্চকর যাত্রায় আমাদের সঙ্গী হতে লাইক ও ফলো দিয়ে সাথেই থাকুন। ধন্যবাদ! ❤️&lt;/p&gt;&lt;p&gt;\n\n\n\n\n\n\n&lt;/p&gt;&lt;p&gt;​#BroxLab #TechHub #DigitalInnovation #MobileTech #CareerGuideline #BangladeshTech&lt;/p&gt;&lt;p&gt;&lt;br&gt;&lt;/p&gt;', '', '', '0', NULL, '2026-01-31 03:12:01', '2026-01-31 16:09:04', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('9', '', '&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;\n\n&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;/div&gt;&lt;div&gt;&lt;div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;div&gt;ছবি: কোলাজ/এএফপি&lt;/div&gt;&lt;/div&gt;&lt;div&gt;&lt;h1&gt;ইসরায়েল–যুক্তরাষ্ট্রের যৌথ হামলায় গতকাল শনিবার ইরানের সর্বোচ্চ নেতা আয়াতুল্লাহ আলী খামেনি নিহত হয়েছেন। আজ রোববার দেশটির সংবাদমাধ্যমে এ খবর জানানো হয়।&lt;/h1&gt;&lt;p&gt;আলী খামেনি নিহত হওয়ার পর ইরানে নেতৃত্বের শূন্যতা তৈরি হয়েছে। গতকাল হামলায় দেশটির সশস্ত্র বাহিনীর প্রধান আবদুল রহিম মুসাভি ও প্রতিরক্ষামন্ত্রী আজিজ নাসিরজাদেহ নিহত হয়েছেন। ইরানের সরকারি বার্তা সংস্থা ইরনা আজ রোববার এ তথ্য নিশ্চিত করেছে।&lt;/p&gt;&lt;p&gt;এর আগে আলী খামেনির নিরাপত্তা উপদেষ্টা আলী শামখানি এবং ইসলামি বিপ্লবী গার্ডের (আইআরজিসি) প্রধান মোহাম্মদ পাকপুর নিহত হওয়ার খবরও নিশ্চিত করেছে ইরান।&lt;/p&gt;&lt;p&gt;ইরনার প্রতিবেদনে বলা হয়, হামলায় ইরানের সশস্ত্র বাহিনীর আরও বেশ কয়েকজন কমান্ডার নিহত হয়েছেন। তাঁদের নাম পরে প্রকাশ করা হবে।&lt;/p&gt;&lt;/div&gt;\n\n&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;div&gt;&lt;p&gt;&lt;/p&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/div&gt;', '', 'post-69a44e2fcb5a5-6576', '1', NULL, '2026-03-01 20:33:19', '2026-03-01 20:34:34', NULL, NULL, NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'draft', NULL, NULL);
