INSERT INTO `posts` (`id`, `title`, `content`, `author`, `slug`, `published`, `reader_indexing`, `created_at`, `updated_at`, `excerpt`, `category_id`, `author_id`, `image`, `image_caption`, `video_url`, `view_count`, `comment_count`, `is_featured`, `is_sticky`, `meta_title`, `meta_description`, `meta_keywords`, `status`, `published_at`, `scheduled_at`) VALUES ('11', 'Welcome to AI Auto Blog', '<p>Welcome to your AI-powered auto blogging system. This system can automatically scrape content from various sources, enhance it with AI, and publish to your blog.</p><h2>Features</h2><ul><li>Automatic content scraping from multiple sources</li><li>AI-powered content enhancement</li><li>SEO optimization</li><li>Automatic duplicate detection</li><li>Multi-language support</li></ul>', '', 'welcome-to-ai-auto-blog', '0', NULL, '2026-03-07 16:23:34', '2026-03-07 16:23:34', 'Welcome to your AI-powered auto blogging system.', '6', NULL, NULL, NULL, NULL, '0', '0', '0', '0', NULL, NULL, NULL, 'published', '2026-03-07 16:23:34', NULL);
